import { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import { useNavigate } from 'react-router-dom';
import NotificationBell from '../components/NotificationBell';
import { registerPatient, getDiagnoses, emailDiagnosis } from '../api';

// Replaces: templates/receptionist.html + static/components/receptionist.js

const TABS = ['Register Patient', 'Completed Diagnoses'];

const EMPTY_FORM = {
  name: '', age: '', gender: 'Male', father_name: '', marital_status: 'Single',
  contact: '', email: '', address: '', cnic: '', occupation: '', nationality: 'Pakistani',
};

export default function Receptionist() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [tab, setTab]           = useState(0);
  const [form, setForm]         = useState(EMPTY_FORM);
  const [diagnoses, setDiagnoses] = useState([]);
  const [msg, setMsg]           = useState({ text: '', type: 'success' });
  const [loading, setLoading]   = useState(false);
  const [emailLoading, setEmailLoading] = useState(null);

  const clinic_id = user.clinic_id;
  const receptionist_id = user.receptionist_id;

  useEffect(() => {
    if (tab === 1) fetchDiagnoses();
  }, [tab]);

  const fetchDiagnoses = async () => {
    const data = await getDiagnoses();
    setDiagnoses(data.diagnoses || []);
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm(f => ({ ...f, [name]: value }));
  };

  const handleRegister = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const payload = { ...form, age: parseInt(form.age), clinic_id };
      await registerPatient(payload);
      flash('Patient registered and assigned to a doctor successfully!', 'success');
      setForm(EMPTY_FORM);
    } catch (err) {
      flash(err.response?.data?.detail || 'Registration failed.', 'error');
    } finally {
      setLoading(false);
    }
  };

  const handleEmailDiagnosis = async (appointment_id, patient_email) => {
    setEmailLoading(appointment_id);
    try {
      await emailDiagnosis({ appointment_id, patient_email });
      flash('Diagnosis email sent!', 'success');
    } catch (err) {
      flash('Failed to send email.', 'error');
    } finally {
      setEmailLoading(null);
    }
  };

  const flash = (text, type = 'success') => {
    setMsg({ text, type });
    setTimeout(() => setMsg({ text: '', type: 'success' }), 4000);
  };

  const handleLogout = () => { logout(); navigate('/login'); };

  return (
    <div style={s.page}>
      <header style={s.header}>
        <div style={s.headerLeft}>
          <span style={s.logo}>💊 CareLine</span>
          <span style={s.role}>Receptionist Portal</span>
        </div>
        <div style={s.headerRight}>
          <span style={s.welcome}>{user.name}</span>
          <NotificationBell role="receptionist" userId={receptionist_id} />
          <button style={s.logoutBtn} onClick={handleLogout}>Logout</button>
        </div>
      </header>

      {msg.text && (
        <div style={{ ...s.flash, background: msg.type === 'error' ? '#d32f2f' : '#388e3c' }}>
          {msg.text}
        </div>
      )}

      <nav style={s.tabs}>
        {TABS.map((t, i) => (
          <button key={t} style={tab === i ? s.tabActive : s.tab} onClick={() => setTab(i)}>{t}</button>
        ))}
      </nav>

      <main style={s.main}>

        {/* TAB 0: REGISTER PATIENT */}
        {tab === 0 && (
          <div style={s.formCard}>
            <h3 style={s.sectionTitle}>Register New Patient</h3>
            <p style={s.hint}>Patient will be automatically assigned to an available doctor at your clinic.</p>
            <form onSubmit={handleRegister} style={s.formGrid}>

              <Field label="Full Name" name="name" value={form.name} onChange={handleChange} required />
              <Field label="Age" name="age" type="number" value={form.age} onChange={handleChange} required />

              <label style={s.label}>Gender
                <select style={s.input} name="gender" value={form.gender} onChange={handleChange}>
                  <option>Male</option>
                  <option>Female</option>
                </select>
              </label>

              <label style={s.label}>Marital Status
                <select style={s.input} name="marital_status" value={form.marital_status} onChange={handleChange}>
                  <option>Single</option>
                  <option>Married</option>
                </select>
              </label>

              <Field label="Father / Spouse Name" name="father_name" value={form.father_name} onChange={handleChange} required />
              <Field label="CNIC (e.g. 35201-1234567-1)" name="cnic" value={form.cnic} onChange={handleChange} placeholder="XXXXX-XXXXXXX-X" required />
              <Field label="Contact (e.g. +923001234567)" name="contact" value={form.contact} onChange={handleChange} placeholder="+92XXXXXXXXXX" required />
              <Field label="Email" name="email" type="email" value={form.email} onChange={handleChange} required />
              <Field label="Occupation" name="occupation" value={form.occupation} onChange={handleChange} />
              <Field label="Nationality" name="nationality" value={form.nationality} onChange={handleChange} required />

              <label style={{ ...s.label, gridColumn: '1 / -1' }}>Address
                <input style={s.input} name="address" value={form.address} onChange={handleChange} required />
              </label>

              <div style={{ gridColumn: '1 / -1', marginTop: 8 }}>
                <button style={s.btn} type="submit" disabled={loading}>
                  {loading ? 'Registering…' : 'Register & Assign Doctor'}
                </button>
              </div>
            </form>
          </div>
        )}

        {/* TAB 1: COMPLETED DIAGNOSES */}
        {tab === 1 && (
          <div>
            <div style={s.tableHeader}>
              <h3 style={{ margin: 0 }}>Completed Diagnoses ({diagnoses.length})</h3>
              <button style={s.refreshBtn} onClick={fetchDiagnoses}>↻ Refresh</button>
            </div>
            {diagnoses.length === 0 ? (
              <p style={s.empty}>No completed diagnoses yet.</p>
            ) : (
              <div style={s.tableWrap}>
                <table style={s.table}>
                  <thead>
                    <tr>
                      <th style={s.th}>Patient</th>
                      <th style={s.th}>Doctor</th>
                      <th style={s.th}>Diagnosis</th>
                      <th style={s.th}>Prescription</th>
                      <th style={s.th}>Completed</th>
                      <th style={s.th}>Email</th>
                    </tr>
                  </thead>
                  <tbody>
                    {diagnoses.map(d => (
                      <tr key={d.id}>
                        <td style={s.td}>
                          <div style={{ fontWeight: 600 }}>{d.patient_name}</div>
                          <div style={s.meta}>{d.patient_contact}</div>
                        </td>
                        <td style={s.td}>{d.doctor_name}</td>
                        <td style={s.td}>{d.diagnosis || '—'}</td>
                        <td style={s.td}>{d.prescription || '—'}</td>
                        <td style={s.td}>{d.ended_at ? new Date(d.ended_at).toLocaleString() : '—'}</td>
                        <td style={s.td}>
                          <button
                            style={s.emailBtn}
                            onClick={() => handleEmailDiagnosis(d.id, d.patient_email)}
                            disabled={emailLoading === d.id}
                          >
                            {emailLoading === d.id ? '…' : '✉ Send'}
                          </button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </div>
        )}
      </main>
    </div>
  );
}

function Field({ label, name, type = 'text', value, onChange, placeholder, required }) {
  return (
    <label style={s.label}>
      {label}
      <input style={s.input} type={type} name={name} value={value}
        onChange={onChange} placeholder={placeholder} required={required} />
    </label>
  );
}

const s = {
  page: { minHeight: '100vh', background: '#f4f6fb', fontFamily: 'Segoe UI,sans-serif' },
  header: { background: '#00897b', color: 'white', padding: '0 24px', display: 'flex', alignItems: 'center', justifyContent: 'space-between', height: 56 },
  headerLeft: { display: 'flex', alignItems: 'center', gap: 12 },
  headerRight: { display: 'flex', alignItems: 'center', gap: 12 },
  logo: { fontWeight: 700, fontSize: '1.1rem' },
  role: { background: 'rgba(255,255,255,.2)', padding: '2px 10px', borderRadius: 12, fontSize: '.8rem' },
  welcome: { fontSize: '.9rem' },
  logoutBtn: { padding: '5px 12px', borderRadius: 6, border: 'none', background: 'rgba(255,255,255,.2)', color: 'white', cursor: 'pointer', fontSize: '.85rem' },
  flash: { color: 'white', padding: '10px 24px', textAlign: 'center', fontWeight: 600 },
  tabs: { display: 'flex', background: 'white', borderBottom: '1px solid #e0e0e0', padding: '0 24px' },
  tab: { padding: '12px 20px', border: 'none', background: 'none', cursor: 'pointer', color: '#666', fontSize: '.9rem', borderBottom: '3px solid transparent' },
  tabActive: { padding: '12px 20px', border: 'none', background: 'none', cursor: 'pointer', color: '#00897b', fontSize: '.9rem', fontWeight: 700, borderBottom: '3px solid #00897b' },
  main: { padding: 24, maxWidth: 1100, margin: '0 auto' },
  formCard: { background: 'white', borderRadius: 12, padding: 28, boxShadow: '0 1px 6px rgba(0,0,0,.08)' },
  sectionTitle: { margin: '0 0 6px', color: '#333' },
  hint: { color: '#888', fontSize: '.85rem', marginBottom: 20 },
  formGrid: { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '14px 20px' },
  label: { display: 'flex', flexDirection: 'column', fontSize: '.85rem', fontWeight: 600, color: '#555', gap: 4 },
  input: { padding: '9px 12px', borderRadius: 7, border: '1px solid #ddd', fontSize: '.9rem' },
  btn: { padding: '11px 24px', borderRadius: 8, border: 'none', background: '#00897b', color: 'white', fontWeight: 700, cursor: 'pointer', fontSize: '1rem' },
  tableHeader: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16 },
  refreshBtn: { padding: '6px 14px', borderRadius: 7, border: '1px solid #ddd', background: 'white', cursor: 'pointer' },
  tableWrap: { overflowX: 'auto' },
  table: { width: '100%', borderCollapse: 'collapse', background: 'white', borderRadius: 10, overflow: 'hidden', boxShadow: '0 1px 4px rgba(0,0,0,.06)' },
  th: { background: '#e0f2f1', padding: '10px 14px', textAlign: 'left', fontSize: '.85rem', color: '#444', fontWeight: 600 },
  td: { padding: '10px 14px', borderBottom: '1px solid #f0f0f0', fontSize: '.85rem', verticalAlign: 'top' },
  meta: { fontSize: '.75rem', color: '#999', marginTop: 2 },
  empty: { color: '#aaa', fontStyle: 'italic', padding: 12 },
  emailBtn: { padding: '5px 12px', borderRadius: 6, border: '1px solid #00897b', color: '#00897b', background: 'white', cursor: 'pointer', fontSize: '.8rem' },
};
